import psycopg2
from psycopg2 import pool
import os


def get_db_connection():
    """
    Create and return a PostgreSQL database connection.
    Uses environment variables for configuration with fallback defaults for development.
    """
    db_host = os.environ.get('DB_HOST', 'localhost')
    db_port = os.environ.get('DB_PORT', '5432')
    db_name = os.environ.get('DB_NAME', 'hackathon_db')
    db_user = os.environ.get('DB_USER', 'admin')
    db_password = os.environ.get('DB_PASSWORD', 'demo123')
    
    connection = psycopg2.connect(
        host=db_host,
        port=db_port,
        database=db_name,
        user=db_user,
        password=db_password
    )
    
    return connection


def get_connection_pool(min_conn=1, max_conn=10):
    """
    Create and return a PostgreSQL connection pool.
    """
    db_host = os.environ.get('DB_HOST', 'localhost')
    db_port = os.environ.get('DB_PORT', '5432')
    db_name = os.environ.get('DB_NAME', 'hackathon_db')
    db_user = os.environ.get('DB_USER', 'admin')
    db_password = os.environ.get('DB_PASSWORD', 'demo123')
    
    connection_pool = psycopg2.pool.SimpleConnectionPool(
        min_conn,
        max_conn,
        host=db_host,
        port=db_port,
        database=db_name,
        user=db_user,
        password=db_password
    )
    
    return connection_pool